 1→import React from 'react';
 2→import { AnalysisResult } from '../types';
 3→import HeroWelcome from '../components/dashboard/HeroWelcome';
 4→import StatsOverview from '../components/dashboard/StatsOverview';
 5→import DualModelExplainer from '../components/dashboard/DualModelExplainer';
 6→import QuickActions from '../components/dashboard/QuickActions';
 7→
 8→interface DashboardProps {
 9→  onBack: () => void;
10→  history: AnalysisResult[];
11→  onView: (analysis: AnalysisResult) => void;
12→  onNavigate: (view: any) => void;
13→}
14→
15→const Dashboard: React.FC<DashboardProps> = ({ onBack, history, onView, onNavigate }) => {
16→  // TODO: These will come from Supabase/auth context later
17→  const userName = 'Utilisateur';
18→  const planName = 'Pro';
19→  const credits = 142;
20→  const maxCredits = 200;
21→
22→  // Derive stats from history if available
23→  const lastAuditScore = history.length > 0 ? history[0].globalScore : null;
24→  const citationCount = history.reduce((sum, h) => sum + (h.aiCitation?.probability > 50 ? 1 : 0), 0);
25→  const languagesCount = 0;
26→  const alertsCount = 0;
27→
28→  return (
29→    <div className="space-y-10 page-enter">
30→      {/* SECTION 1 — Hero Welcome */}
31→      <HeroWelcome
32→        userName={userName}
33→        planName={planName}
34→        credits={credits}
35→        maxCredits={maxCredits}
36→        onNavigate={onNavigate}
37→      />
38→
39→      {/* SECTION 2 — Stats rapides */}
40→      <StatsOverview
41→        stats={{
42→          aeoScore: lastAuditScore,
43→          citationCount,
44→          languagesAnalyzed: languagesCount,
45→          activeAlerts: alertsCount,
46→        }}
47→      />
48→
49→      {/* SECTION 3 — Double modele economique */}
50→      <DualModelExplainer
51→        credits={credits}
52→        maxCredits={maxCredits}
53→        planName={planName}
54→        currentPlan={planName.toLowerCase() as 'free' | 'starter' | 'pro' | 'agence'}
55→        onNavigate={onNavigate}
56→      />
57→
58→      {/* SECTION 4 — Actions rapides */}
59→      <QuickActions
60→        credits={credits}
61→        onNavigate={onNavigate}
62→      />
63→    </div>
64→  );
65→};
66→
67→export default Dashboard;
