299→                                  color: cat.score >= 80 ? '#16a34a' : cat.score >= 50 ? '#7c3aed' : '#dc2626',
300→                                  border: `2px solid ${cat.score >= 80 ? '#bbf7d0' : cat.score >= 50 ? '#c4b5fd' : '#fca5a5'}`,
