302→                                  {cat.score}
303→                              </div>
304→                              <span style={{ fontSize: '15px', fontWeight: 700, color: '#111827', margin: 0, flex: 1 }}>{cat.name}</span>
305→                              <span style={{ fontSize: '11px', color: '#9ca3af', fontWeight: 500 }}>{cat.items.length} critères</span>
306→                          </div>
307→                          {/* Criteria Table */}
308→                          <table style={{ width: '100%', borderCollapse: 'collapse', border: '1px solid #e5e7eb', borderRadius: '6px', overflow: 'hidden' }}>
309→                              <thead>
310→                                  <tr style={{ backgroundColor: '#f9fafb' }}>
311→                                      <th style={{ padding: '7px 12px', textAlign: 'center', fontSize: '10px', fontWeight: 600, color: '#9ca3af', textTransform: 'uppercase', borderBottom: '1px solid #e5e7eb', width: '36px' }}>#</th>
312→                                      <th style={{ padding: '7px 12px', textAlign: 'left', fontSize: '10px', fontWeight: 600, color: '#9ca3af', textTransform: 'uppercase', borderBottom: '1px solid #e5e7eb' }}>Critère évalué</th>
313→                                      <th style={{ padding: '7px 12px', textAlign: 'center', fontSize: '10px', fontWeight: 600, color: '#9ca3af', textTransform: 'uppercase', borderBottom: '1px solid #e5e7eb', width: '130px' }}>Statut</th>
314→                                  </tr>
315→                              </thead>
316→                              <tbody>
317→                                  {cat.items.map((item, idx) => (
318→                                      <tr key={idx} style={{ backgroundColor: idx % 2 === 0 ? '#ffffff' : '#fafafa' }}>
319→                                          <td style={{ padding: '7px 12px', textAlign: 'center', fontSize: '11px', color: '#9ca3af', borderBottom: '1px solid #f3f4f6' }}>{idx + 1}</td>
320→                                          <td style={{ padding: '7px 12px', fontSize: '12px', color: '#374151', borderBottom: '1px solid #f3f4f6' }}>{item.message}</td>
321→                                          <td style={{ padding: '7px 12px', textAlign: 'center', borderBottom: '1px solid #f3f4f6' }}>
322→                                              <span style={{
323→                                                  display: 'inline-block', padding: '2px 10px', borderRadius: '10px', fontSize: '10px', fontWeight: 700, letterSpacing: '0.02em',
324→                                                  backgroundColor: item.status === 'success' ? '#f0fdf4' : item.status === 'error' ? '#fef2f2' : '#fffbeb',
325→                                                  color: item.status === 'success' ? '#16a34a' : item.status === 'error' ? '#dc2626' : '#d97706',
326→                                                  border: `1px solid ${item.status === 'success' ? '#bbf7d0' : item.status === 'error' ? '#fecaca' : '#fde68a'}`,
327→                                              }}>
328→                                                  {item.status === 'success' ? '✓ Conforme' : item.status === 'error' ? '✗ Non conforme' : '⚠ À optimiser'}
329→                                              </span>
330→                                          </td>
331→                                      </tr>
332→                                  ))}
333→                              </tbody>
334→                          </table>
335→                      </div>
336→                  ))}
337→              </div>
338→
339→              {/* Footer */}
340→              <div className="mt-20 pt-8 border-t border-gray-200 flex justify-between items-center text-gray-400 text-sm">
341→                  <div className="flex items-center gap-2">
342→                      <div className="w-6 h-6 rounded bg-gray-200 flex items-center justify-center text-gray-500 font-serif font-bold text-xs">C</div>
343→                      <span>Généré par CitedBy.ai</span>
344→                  </div>
345→                  <p>Document confidentiel - Usage interne uniquement</p>
346→              </div>
347→            </div>
348→          </div>
349→      </div>
350→    </div>
351→  );
352→};
353→
354→export { Results };
355→export default Results;
