  1→import React, { useState, useMemo } from 'react';
  2→import { AnalysisResult, Recommendation, GeneratedSolution, User } from '../types';
  3→import { generateSolution } from '../services/generator';
  4→import RecommendationCard from '../components/RecommendationCard';
  5→import GenerationModal from '../components/GenerationModal';
  6→import ScoreProjection from '../components/ScoreProjection';
