  const [generatedSolution, setGeneratedSolution] = useState<GeneratedSolution | null>(null);

  // Score Projection — solution selection state
  const [selectedSolutions, setSelectedSolutions] = useState<Set<string>>(new Set());

  const toggleSolution = (solId: string) => {
    setSelectedSolutions(prev => {
      const next = new Set(prev);
      if (next.has(solId)) next.delete(solId);
      else next.add(solId);
      return next;
    });
  };

  const selectAll = () => {
    if (data) setSelectedSolutions(new Set(data.recommendations.map(r => r.id)));
  };

  const deselectAll = () => {
    setSelectedSolutions(new Set());
  };

  const getSolutionCost = (priority: string): number => {
    switch (priority) {
      case 'critical': return 5;
      case 'high': return 4;
      case 'medium': return 3;
      case 'low': return 1;
      default: return 3;
    }
  };

  const totalRemainingCost = useMemo(() => {
    if (!data) return 0;
    return data.recommendations.reduce((acc, rec) => {
        if (data.generatedSolutions && data.generatedSolutions[rec.id]) return acc;
        return acc + getSolutionCost(rec.priority);
    }, 0);
  }, [data?.recommendations, data?.generatedSolutions]);

  const handleApplyRecommendation = async (rec: Recommendation) => {
    const cost = getSolutionCost(rec.priority);

    const success = onDeductCredits(cost);
    if (!success) {
      return;
    }

    setIsModalOpen(true);
    setIsGeneratingSolution(true);
    setGeneratedSolution(null);

    try {
      const solution = await generateSolution(rec, data.url);
      setGeneratedSolution(solution);
      onSaveSolution(data.timestamp, rec.id, solution);

    } catch (error) {
      console.error("Error generating solution", error);
      setGeneratedSolution({
        title: t.actionPlan.generationError,
        explanation: t.actionPlan.aiUnavailable,
        type: 'text',
        content: t.actionPlan.retryLater,
        implementationSteps: [t.actionPlan.retryOperation]
      });
    } finally {
      setIsGeneratingSolution(false);
    }
  };

  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
    setGeneratedSolution(solution);
    setIsModalOpen(true);
  };

  if (!data) {
    return (
        <div className="w-full px-4 py-16 min-h-[80vh] flex flex-col items-center justify-center text-center">
            <div className="w-12 h-12 rounded-xl bg-white/[0.06] flex items-center justify-center mb-4">
                <Zap size={24} className="text-[var(--text-tertiary)]" />
            </div>
            <h2 className="text-[var(--text-primary)] font-medium mt-2">{t.actionPlan.noActivePlan}</h2>
            <p className="text-sm text-[var(--text-tertiary)] mt-1 max-w-sm">
                {t.actionPlan.noActivePlanDesc}
            </p>
            <button
                onClick={onNavigateToAnalysis}
                className="mt-4 inline-flex items-center px-4 py-2 bg-white text-black text-sm font-medium rounded-lg hover:bg-gray-200 transition-all duration-150 cursor-pointer"
            >
                {t.actionPlan.launchAnalysis}
            </button>
        </div>
    );
  }

  const criticalRecs = data.recommendations.filter(r => r.priority === 'critical');
  const otherRecs = data.recommendations.filter(r => r.priority !== 'critical');

  return (
    <div className="page-enter">
      <PageHeader title={t.actionPlan.title} description={t.actionPlan.subtitle} />

      <GenerationModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        isLoading={isGeneratingSolution}
        solution={generatedSolution}
      />

      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4 bg-white/[0.03] p-4 rounded-xl border border-white/[0.06]">
        <div>
            <p className="text-[13px] text-[var(--text-tertiary)]">{data.recommendations.length} {t.actionPlan.optimizationPoints} <span className="text-[var(--text-secondary)] font-medium">{new URL(data.url).hostname}</span></p>
        </div>
        <div className="flex items-center gap-3">
            <span className="text-[11px] font-medium px-2 py-0.5 rounded-md bg-white/[0.06] text-[var(--text-secondary)] border border-white/[0.06]">
            {t.actionPlan.unitCost} <span className="text-[var(--accent-text)] font-semibold">{t.actionPlan.unitCostRange}</span>
            </span>
        </div>
      </div>

      {/* Score Projection — before/after panel */}
      <ScoreProjection
        categories={data.categories}
        recommendations={data.recommendations}
        selectedSolutions={selectedSolutions}
        globalScore={data.globalScore}
      />

      {/* Selection controls */}
      <div className="flex items-center gap-3 mb-6">
        <button
          onClick={selectAll}
          className="flex items-center gap-1.5 text-[13px] text-[var(--accent-text)] hover:text-[var(--accent)] transition-colors"
        >
          <CheckSquare size={14} />
          {t.actionPlan.selectAll}
        </button>
        <span className="text-[var(--border-default)]">|</span>
        <button
          onClick={deselectAll}
          className="flex items-center gap-1.5 text-[13px] text-[var(--text-tertiary)] hover:text-[var(--text-secondary)] transition-colors"
        >
          <Square size={14} />
          {t.actionPlan.deselectAll}
        </button>
        <span className="ml-auto text-[13px] text-[var(--text-disabled)]">
          {selectedSolutions.size} / {data.recommendations.length} {t.actionPlan.solutions}
        </span>
      </div>

      {/* Critical Recommendations Section */}
      {criticalRecs.length > 0 && (
            <div className="mb-12">
                <h3 className="text-[15px] font-semibold text-[var(--error)] mb-4 flex items-center gap-2">
                <AlertTriangle size={18} />
                {t.actionPlan.criticalUrgencies} ({criticalRecs.length})
                </h3>
                <div className="space-y-3">
                {criticalRecs.map(rec => (
                    <div key={rec.id} className="flex items-start gap-3">
                      <label className="pt-5 cursor-pointer flex-shrink-0">
                        <input
                          type="checkbox"
                          checked={selectedSolutions.has(rec.id)}
                          onChange={() => toggleSolution(rec.id)}
                          className="w-4 h-4 rounded border-[var(--border-strong)] bg-white/[0.06] cursor-pointer accent-[var(--accent)]"
                        />
                      </label>
                      <div className="flex-1 min-w-0">
                        <RecommendationCard
                            rec={rec}
                            cost={getSolutionCost(rec.priority)}
                            onApply={handleApplyRecommendation}
                            existingSolution={data.generatedSolutions?.[rec.id]}
                            onView={handleOpenStoredSolution}
                        />
                      </div>
                    </div>
                ))}
                </div>
            </div>
      )}

      {/* Standard Recommendations Section */}
      {otherRecs.length > 0 && (
            <div className="mt-8">
                <h3 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4 flex items-center gap-2">
                <Zap size={18} className="text-[var(--accent-text)]" />
                {t.actionPlan.recommendedOptimizations} ({otherRecs.length})
                </h3>
                <div className="space-y-3">
                {otherRecs.map(rec => (
                    <div key={rec.id} className="flex items-start gap-3">
                      <label className="pt-5 cursor-pointer flex-shrink-0">
                        <input
                          type="checkbox"
                          checked={selectedSolutions.has(rec.id)}
                          onChange={() => toggleSolution(rec.id)}
                          className="w-4 h-4 rounded border-[var(--border-strong)] bg-white/[0.06] cursor-pointer accent-[var(--accent)]"
                        />
                      </label>
                      <div className="flex-1 min-w-0">
                        <RecommendationCard
                            rec={rec}
                            cost={getSolutionCost(rec.priority)}
                            onApply={handleApplyRecommendation}
                            existingSolution={data.generatedSolutions?.[rec.id]}
                            onView={handleOpenStoredSolution}
                        />
                      </div>
                    </div>
                ))}
                </div>
            </div>
      )}

      {/* TOTAL COST SUMMARY - CLICKABLE FOR RECHARGE */}
      {totalRemainingCost > 0 && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 md:translate-x-0 md:left-auto md:right-8 w-[90%] md:w-auto z-40">
            <button
                onClick={onNavigateToRecharge}
                className="p-4 rounded-2xl border border-white/[0.06] bg-[var(--bg-base)]/90 backdrop-blur-md shadow-2xl flex items-center gap-6 w-full md:w-auto hover:border-[var(--accent)]/50 transition-all cursor-pointer text-left group"
            >
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-[var(--accent-subtle)] flex items-center justify-center text-[var(--accent-text)] group-hover:scale-110 transition-transform">
                        <Fuel size={18} />
                    </div>
                    <div>
                        <p className="text-[11px] text-[var(--text-disabled)] uppercase font-semibold tracking-wider">{t.actionPlan.remainingCost}</p>
                        <div className="text-xl font-bold text-[var(--text-primary)]">{totalRemainingCost} <span className="text-[11px] font-medium text-[var(--text-disabled)]">{t.actionPlan.creditsLabel}</span></div>
                    </div>
                </div>

                {user && (
                    <div className={`text-[11px] font-medium px-3 py-1.5 rounded-full border flex items-center gap-2 ${user.credits >= totalRemainingCost ? 'bg-[var(--accent-subtle)] text-[var(--accent-text)] border-white/[0.06]' : 'bg-red-500/10 text-[var(--error)] border-red-500/20'}`}>
                        {user.credits >= totalRemainingCost
                            ? t.actionPlan.sufficientBalance
                            : `${t.actionPlan.missing} ${totalRemainingCost - user.credits}`
                        }
                        {user.credits < totalRemainingCost && <ArrowRight size={12} />}
                    </div>
                )}
            </button>
        </div>
      )}
    </div>
  );
};

export default ActionPlan;

import React, { useState, useMemo, useEffect } from 'react';
import { Project, User, AnalysisResult, GeneratedSolution } from '../types';
import { useTranslation } from '../i18n/context';
import { Plus, Search, Globe, TrendingUp, Calendar, ArrowUpRight, BarChart3, ChevronDown, Zap, Activity, ArrowRight, Wrench, FileText, Shield, ExternalLink, Clock, LayoutDashboard, Bot, Lock, ChevronLeft, ChevronRight, Eye, RefreshCw, ClipboardList, ArrowLeft, ClipboardCheck, Archive, Code } from 'lucide-react';
import ScoreRing from '../components/ScoreRing';
import { Results } from './Results';
import ActionPlan from './ActionPlan';
import GenerationModal from '../components/GenerationModal';
import PageHeader from '../components/layout/PageHeader';

interface ProjectsProps {
  onBack: () => void;
  onNavigateToAnalysis: () => void;
  user: User | null;
  history: AnalysisResult[];
  onViewAnalysis: (result: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview') => void;
  projectCount: number;
  maxProjects: number;
  onNavigateToPlan: () => void;
  onDeductCredits: (amount: number) => boolean;
  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
  onNewAnalysis: () => void;
  onNavigateToRecharge: () => void;
  initialUrl?: string;
  initialTab?: string;
}

// Helper to convert AnalysisResult to Project format
const mapAnalysisToProject = (analysis: AnalysisResult, index: number): Project => {
  const hostname = new URL(analysis.url).hostname;
  return {
    id: `proj_${index}_${hostname}`,
    name: hostname,
    domain: analysis.url,
    status: 'active',
    lastRun: analysis.timestamp,
    visibilityScore: analysis.globalScore,
    trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5),
    nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
  };
};

const Projects: React.FC<ProjectsProps> = ({ onBack, onNavigateToAnalysis, user, history, onViewAnalysis, projectCount, maxProjects, onNavigateToPlan, onDeductCredits, onSaveSolution, onNewAnalysis, onNavigateToRecharge, initialUrl, initialTab }) => {
  const { t } = useTranslation();

  // Navigation internal state: monitoring | report | action-plan | archives
  const [activeTab, setActiveTab] = useState<'monitoring' | 'report' | 'action-plan' | 'archives'>(() => {
    if (initialTab === 'archives') return 'archives';
    if (initialTab === 'recommendations' || initialTab === 'action-plan') return 'action-plan';
    if (initialTab === 'details' || initialTab === 'report') return 'report';
    return 'monitoring';
  });

  useEffect(() => {
    if (initialTab === 'archives') setActiveTab('archives');
    else if (initialTab === 'recommendations') setActiveTab('action-plan');
    else if (initialTab === 'details' || initialTab === 'report') setActiveTab('report');
    else if (initialTab === 'overview') setActiveTab('monitoring');
  }, [initialTab]);

  // Use history to build project list, defaulting to mock if empty for demo
  const projects = useMemo(() => {
    if (history.length > 0) {
      // Deduplicate by URL hostname, keeping the most recent
      const uniqueMap = new Map<string, AnalysisResult>();
      history.forEach(item => {
        try {
            const host = new URL(item.url).hostname;
            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
                uniqueMap.set(host, item);
            }
        } catch(e) {}
      });
      return Array.from(uniqueMap.values()).map((analysis, index) => mapAnalysisToProject(analysis, index));
    } else {
      // Mock data fallback if no history
      return [
        {
          id: 'demo_1',
          name: t.projectsPage.demoSiteName,
          domain: 'https://demo-site.com',
          status: 'active',
          lastRun: new Date().toISOString(),
          visibilityScore: 45,
          trend: 0,
          nextRun: new Date(Date.now() + 86400000).toISOString()
        }
      ] as Project[];
    }
  }, [history, t]);

  const [selectedProjectId, setSelectedProjectId] = useState<string>(() => {
    if (initialUrl && projects.length > 0) {
        try {
            const targetHost = new URL(initialUrl).hostname;
            const found = projects.find(p => p.name === targetHost);
            if (found) return found.id;
        } catch(e) {}
    }
    return projects[0]?.id || '';
  });

  const [selectedAnalysisState, setSelectedAnalysisState] = useState<AnalysisResult | null>(null);

  // States for viewing archive modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentSolution, setCurrentSolution] = useState<GeneratedSolution | null>(null);

  const currentProject = projects.find(p => p.id === selectedProjectId) || projects[0];

  // Filter history for current project ONLY
  const projectHistory = useMemo(() => {
    return history
      .filter(h => {
          try { return new URL(h.url).hostname === currentProject.name; }
          catch(e) { return false; }
      })
      .sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }, [history, currentProject]);

  // Reset selected analysis when project changes
  useEffect(() => {
    setSelectedAnalysisState(null);
  }, [selectedProjectId]);

  // The analysis to display (either user-selected from table, or the latest one)
  const activeAnalysis = selectedAnalysisState || projectHistory[0];

  const handleOpenStoredSolution = (solution: GeneratedSolution) => {
    setCurrentSolution(solution);
    setIsModalOpen(true);
  };

  // Calculate Pillar Scores from real categories if available
  const getPillarScores = () => {
    if (!activeAnalysis) {
      return {
        tech: 50,
        sem: 50,
        auth: 50
      };
    }

    const cats = activeAnalysis.categories;

    const techScore = Math.round(
      ((cats['technical']?.score || 0) + (cats['ux']?.score || 0) + (cats['freshness']?.score || 0)) / 3
    );

    const semScore = Math.round(
      ((cats['semantic']?.score || 0) + (cats['content']?.score || 0) + (cats['geo']?.score || 0) + (cats['media']?.score || 0)) / 4
    );

    const authScore = Math.round(
      ((cats['entity']?.score || 0) + (cats['structured_data']?.score || 0) + (cats['trust']?.score || 0)) / 3
    );

    return { tech: techScore, sem: semScore, auth: authScore };
  };

  const pillarScores = getPillarScores();

  const getScoreColor = (score: number) => {
    if (score >= 80) return 'text-white';
    if (score >= 60) return 'text-purple-400';
    return 'text-blue-400';
  };

  const getBarColor = (score: number) => {
    if (score >= 80) return 'bg-purple-400';
    if (score >= 60) return 'bg-purple-500';
    return 'bg-blue-400';
  };

  const handleSwitchToReport = () => {
    if (activeAnalysis) {
        setActiveTab('report');
    } else {
        alert(t.projectsPage.launchAnalysisForReport);
        onNavigateToAnalysis();
    }
  };

  const handleSwitchToActionPlan = () => {
    if (activeAnalysis) {
        setActiveTab('action-plan');
    } else {
        alert(t.projectsPage.launchAnalysisForPlan);
        onNavigateToAnalysis();
    }
  };

  const handleSwitchToArchives = () => {
    if (activeAnalysis) {
        setActiveTab('archives');
    } else {
        alert(t.projectsPage.launchAnalysisForArchives);
        onNavigateToAnalysis();
    }
  };

  const handleBackToMonitoring = () => {
    setActiveTab('monitoring');
  };

  const isLimitReached = projectCount >= maxProjects;

  // -- SHARED TABS BAR (rendered on all views) --
  const [isProjectDropdownOpen, setIsProjectDropdownOpen] = useState(false);

  const renderTabsBar = () => (
    <div className="w-full px-4 pt-8">
      {/* URL Selector — prominent, above tabs */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center gap-3 mb-6">
        <div className="relative">
          <button
            onClick={() => setIsProjectDropdownOpen(!isProjectDropdownOpen)}
            className="flex items-center gap-3 px-5 py-2.5 bg-gradient-to-r from-purple-500/10 to-violet-500/10 hover:from-purple-500/20 hover:to-violet-500/20 border border-purple-500/30 rounded-2xl transition-all text-sm font-bold group"
          >
            <Globe size={16} className="text-purple-400" />
            <span className="text-white truncate max-w-[280px]">{currentProject.name}</span>
            <ChevronDown size={14} className={`text-purple-400 transition-transform ${isProjectDropdownOpen ? 'rotate-180' : ''}`} />
          </button>
          {isProjectDropdownOpen && (
            <>
              <div className="fixed inset-0 z-40" onClick={() => setIsProjectDropdownOpen(false)} />
              <div className="absolute top-full left-0 mt-2 w-72 bg-[#1a1d24] border border-purple-500/20 rounded-2xl shadow-2xl shadow-purple-500/10 z-50 p-1.5 animate-in fade-in slide-in-from-top-2 duration-200">
                <p className="px-3 py-1.5 text-[10px] uppercase tracking-wider text-gray-500 font-bold">{t.projectsPage.scannedProjects}</p>
                {projects.map(p => (
                  <button
                    key={p.id}
                    onClick={() => { setSelectedProjectId(p.id); setIsProjectDropdownOpen(false); }}
                    className={`w-full text-left px-3 py-2.5 rounded-xl text-sm flex items-center gap-2.5 transition-colors ${
                      p.id === selectedProjectId
                        ? 'bg-purple-500/15 text-purple-300 font-bold'
                        : 'text-gray-300 hover:bg-white/[0.06]'
                    }`}
                  >
                    <Globe size={14} className={p.id === selectedProjectId ? 'text-purple-400' : 'text-[var(--text-disabled)]'} />
                    {p.name}
                  </button>
                ))}
                <div className="border-t border-[var(--border-subtle)] mt-1.5 pt-1.5">
                  <button
                    onClick={() => { setIsProjectDropdownOpen(false); onNavigateToAnalysis(); }}
                    className="w-full text-left px-3 py-2.5 rounded-xl text-sm text-gray-500 hover:text-white hover:bg-white/[0.06] flex items-center gap-2.5 transition-colors"
                  >
                    <Plus size={14} /> {t.projectsPage.scanNewUrl}
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
        {currentProject && (
          <span className="text-xs text-gray-500 flex items-center gap-1.5">
            <span className="w-1.5 h-1.5 bg-purple-400 rounded-full animate-pulse"></span>
            {t.projectsPage.monitoringActive}
          </span>
        )}
      </div>

      {/* Tabs */}
      <div className="flex gap-6 mb-8 border-b border-white/[0.06] overflow-x-auto">
          <button
            onClick={() => setActiveTab('monitoring')}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'monitoring'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <Activity size={18} className={activeTab === 'monitoring' ? 'text-purple-400' : 'opacity-50'} />
            {t.projectsPage.overview}
          </button>

          <button
            onClick={handleSwitchToReport}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'report'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <ClipboardList size={18} className={activeTab === 'report' ? 'text-purple-400' : 'opacity-50'} />
            {t.projectsPage.auditReport}
          </button>

          <button
            onClick={handleSwitchToActionPlan}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'action-plan'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <Zap size={18} className={activeTab === 'action-plan' ? 'text-purple-400 fill-primary' : 'opacity-50'} />
            {t.projectsPage.actionPlanTab}
            {activeAnalysis && activeAnalysis.recommendations.length > 0 && (
                <span className="bg-primary text-black text-[10px] px-1.5 py-0.5 rounded-full ml-1.5">
                    {activeAnalysis.recommendations.length}
                </span>
            )}
          </button>

          <button
            onClick={handleSwitchToArchives}
            className={`pb-3 px-4 text-sm font-bold border-b-2 transition-all duration-200 flex items-center gap-2 whitespace-nowrap ${
              activeTab === 'archives'
                ? 'border-primary text-white'
                : 'border-transparent text-gray-500 hover:text-gray-300'
            }`}
          >
            <Archive size={18} className={activeTab === 'archives' ? 'text-purple-400' : 'opacity-50'} />
            {t.projectsPage.solutionArchives}
          </button>
      </div>
    </div>
  );

  // -- RENDER : REPORT VIEW (RESULTS) --
  if (activeTab === 'report' && activeAnalysis) {
      return (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              {renderTabsBar()}
              <Results
                data={activeAnalysis}
                onBack={handleBackToMonitoring}
                user={user}
                onDeductCredits={onDeductCredits}
                onSaveSolution={onSaveSolution}
                onNewAnalysis={onNewAnalysis}
              />
          </div>
      );
  }

  // -- RENDER : ACTION PLAN VIEW --
  if (activeTab === 'action-plan' && activeAnalysis) {
      return (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              {renderTabsBar()}
              <ActionPlan
                data={activeAnalysis}
                user={user}
                onDeductCredits={onDeductCredits}
                onSaveSolution={onSaveSolution}
                onNavigateToAnalysis={onNewAnalysis}
                onNavigateToRecharge={onNavigateToRecharge}
              />
          </div>
      );
  }

  // -- RENDER : ARCHIVES SOLUTIONS VIEW --
  if (activeTab === 'archives' && activeAnalysis) {
      return (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300 w-full">
              {renderTabsBar()}
              <GenerationModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                isLoading={false}
                solution={currentSolution}
              />
              <div className="px-4 pb-8">

              <div className="flex items-center gap-3 mb-8">
                  <div className="w-10 h-10 rounded-full bg-purple-500/20 flex items-center justify-center text-purple-300 border border-purple-500/30">
                      <Archive size={20} />
                  </div>
                  <div>
                      <h3 className="text-xl font-sans font-bold text-white">{t.projectsPage.solutionArchives}</h3>
                      <p className="text-sm text-gray-500">{t.projectsPage.archivesDesc}</p>
                  </div>
              </div>

              {activeAnalysis.generatedSolutions && Object.keys(activeAnalysis.generatedSolutions).length > 0 ? (
                  <div className="grid md:grid-cols-2 gap-6">
                      {Object.entries(activeAnalysis.generatedSolutions).map(([recId, sol], idx) => {
                        const solution = sol as GeneratedSolution & { timestamp: string };
