  const [activeConversationId, setActiveConversationId] = useState<string>('conv-1');
  const [searchQuery, setSearchQuery] = useState('');
  const [filterTab, setFilterTab] = useState<'all' | 'unread' | 'support'>('all');
  const [messageInput, setMessageInput] = useState('');
  const [showMobileThread, setShowMobileThread] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [showEmojiHint, setShowEmojiHint] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const activeConversation = conversations.find(c => c.id === activeConversationId) || conversations[0];

  const totalUnread = conversations.reduce((sum, c) => sum + c.unread, 0);

  // Filter conversations
  const filteredConversations = conversations.filter(c => {
    const matchesSearch =
      c.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      c.lastMessage.toLowerCase().includes(searchQuery.toLowerCase());

    if (filterTab === 'unread') return matchesSearch && c.unread > 0;
    if (filterTab === 'support') return matchesSearch && c.category === 'support';
    return matchesSearch;
  });

  // Scroll to bottom on conversation change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [activeConversationId, activeConversation.messages.length]);

  // Simulate typing indicator when switching conversations
  useEffect(() => {
    if (activeConversation.online) {
      const timer = setTimeout(() => {
        setIsTyping(true);
        const stop = setTimeout(() => setIsTyping(false), 2500);
        return () => clearTimeout(stop);
      }, 3000);
      return () => clearTimeout(timer);
    }
    setIsTyping(false);
  }, [activeConversationId, activeConversation.online]);

  const handleSelectConversation = (id: string) => {
    setActiveConversationId(id);
    setShowMobileThread(true);
  };

  const handleSendMessage = () => {
    if (!messageInput.trim()) return;
    // In a real app this would send to backend; here we just clear input
    setMessageInput('');
    inputRef.current?.focus();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // ---------------------------------------------------------------------------
  // SUB-COMPONENTS
  // ---------------------------------------------------------------------------

  const ConversationItem = ({ conv }: { conv: Conversation }) => {
    const isActive = conv.id === activeConversationId;
    return (
      <button
        onClick={() => handleSelectConversation(conv.id)}
        className={`w-full flex items-start gap-3 p-4 transition-all text-left rounded-xl group ${
          isActive
            ? 'bg-purple-500/10 border border-purple-500/20'
            : 'hover:bg-white/[0.03] border border-transparent'
        }`}
      >
        {/* Avatar */}
        <div className="relative flex-shrink-0">
          <div
            className={`w-11 h-11 rounded-full flex items-center justify-center text-sm font-bold ${
              isActive
                ? 'bg-purple-500/20 text-purple-300 border border-purple-500/30'
                : 'bg-white/[0.06] text-gray-300 border border-white/[0.06]'
            }`}
          >
            {conv.avatar}
          </div>
          {conv.online && (
            <span className="absolute -bottom-0.5 -right-0.5 w-3.5 h-3.5 bg-green-500 rounded-full border-2 border-[var(--bg-surface)]" />
          )}
        </div>

        {/* Text */}
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-center mb-0.5">
            <span className={`text-sm font-semibold truncate ${isActive ? 'text-white' : 'text-gray-200'}`}>
              {conv.name}
            </span>
            <span className="text-[11px] text-gray-500 flex-shrink-0 ml-2">{conv.timestamp}</span>
          </div>
          <p className="text-xs text-gray-500 truncate leading-relaxed">{conv.lastMessage}</p>
        </div>

        {/* Unread badge */}
        {conv.unread > 0 && (
          <span className="flex-shrink-0 mt-1 w-5 h-5 flex items-center justify-center bg-purple-500 text-white text-[10px] font-bold rounded-full">
            {conv.unread}
          </span>
        )}
      </button>
    );
  };

  const MessageBubble = ({ msg, isLast }: { msg: Message; isLast: boolean }) => {
    const isMine = msg.sender === 'me';
    return (
      <div className={`flex ${isMine ? 'justify-end' : 'justify-start'} mb-2 group`}>
        <div className={`max-w-[75%] ${isMine ? 'order-2' : 'order-1'}`}>
          <div
            className={`px-4 py-2.5 text-sm leading-relaxed ${
              isMine
                ? 'bg-purple-500/20 text-purple-100 rounded-2xl rounded-br-md border border-purple-500/20'
                : 'bg-white/[0.05] text-gray-300 rounded-2xl rounded-bl-md border border-[var(--border-subtle)]'
            }`}
          >
            {msg.content}
          </div>
          <div className={`flex items-center gap-1 mt-1 ${isMine ? 'justify-end' : 'justify-start'}`}>
            <span className="text-[10px] text-[var(--text-disabled)]">{msg.timestamp}</span>
            {isMine && (
              msg.read
                ? <CheckCheck size={12} className="text-purple-400" />
                : <Check size={12} className="text-[var(--text-disabled)]" />
            )}
          </div>
        </div>
      </div>
    );
  };

  // ---------------------------------------------------------------------------
  // RENDER: Conversation List Panel
  // ---------------------------------------------------------------------------

  const ConversationListPanel = (
    <div
      className={`flex flex-col h-full ${
        showMobileThread ? 'hidden lg:flex' : 'flex'
      } lg:w-[380px] lg:min-w-[340px] lg:border-r lg:border-[var(--border-subtle)]`}
    >
      {/* Search */}
      <div className="p-4 border-b border-[var(--border-subtle)]">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input
            type="text"
            placeholder={t.messages.searchPlaceholder}
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="w-full bg-white/[0.03] border border-white/[0.06] rounded-xl pl-10 pr-4 py-2.5 text-sm text-white placeholder-gray-500 focus:outline-none focus:border-purple-500/40 transition-colors"
          />
        </div>

        {/* Filter tabs */}
        <div className="flex gap-2 mt-3">
          {([
            { key: 'all', label: t.messages.filterAll },
            { key: 'unread', label: t.messages.filterUnread },
            { key: 'support', label: t.messages.filterSupport },
          ] as const).map(tab => (
            <button
              key={tab.key}
              onClick={() => setFilterTab(tab.key)}
              className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${
                filterTab === tab.key
                  ? 'bg-purple-500/15 text-purple-300 border border-purple-500/25'
                  : 'bg-white/[0.03] text-gray-500 border border-[var(--border-subtle)] hover:text-gray-300'
              }`}
            >
              {tab.label}
              {tab.key === 'unread' && totalUnread > 0 && (
                <span className="ml-1.5 text-[10px] bg-purple-500 text-white px-1.5 py-0.5 rounded-full">{totalUnread}</span>
              )}
            </button>
          ))}
        </div>
      </div>

      {/* Conversation list */}
      <div className="flex-1 overflow-y-auto px-2 py-2 space-y-1 custom-scrollbar">
        {filteredConversations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 text-center">
            <MessageSquare size={32} className="text-[var(--text-disabled)] mb-3" />
            <p className="text-sm text-gray-500">{t.messages.noConversation}</p>
          </div>
        ) : (
          filteredConversations.map(conv => (
            <ConversationItem key={conv.id} conv={conv} />
          ))
        )}
      </div>
    </div>
  );

  // ---------------------------------------------------------------------------
  // RENDER: Message Thread Panel
  // ---------------------------------------------------------------------------

  const MessageThreadPanel = (
    <div
      className={`flex flex-col flex-1 h-full ${
        showMobileThread ? 'flex' : 'hidden lg:flex'
      }`}
    >
      {/* Thread header */}
      <div className="flex items-center justify-between px-5 py-4 border-b border-[var(--border-subtle)]">
        <div className="flex items-center gap-3">
          {/* Mobile back */}
          <button
            onClick={() => setShowMobileThread(false)}
            className="lg:hidden p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-400 transition-colors mr-1"
          >
            <ArrowLeft size={18} />
          </button>
          {/* Avatar */}
          <div className="relative">
            <div className="w-10 h-10 rounded-full bg-purple-500/15 border border-purple-500/25 flex items-center justify-center text-sm font-bold text-purple-300">
              {activeConversation.avatar}
            </div>
            {activeConversation.online && (
              <span className="absolute -bottom-0.5 -right-0.5 w-3 h-3 bg-green-500 rounded-full border-2 border-[var(--bg-surface)]" />
            )}
          </div>
          <div>
            <h3 className="text-sm font-semibold text-white">{activeConversation.name}</h3>
            <p className="text-[11px] text-gray-500">
              {activeConversation.online ? (
                <span className="text-green-400 flex items-center gap-1">
                  <Circle size={6} className="fill-green-400" /> {t.messages.online}
                </span>
              ) : (
                t.messages.offline
              )}
              {' — '}{activeConversation.role}
            </p>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button className="p-2 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors hidden sm:block">
            <Phone size={16} />
          </button>
          <button className="p-2 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors hidden sm:block">
            <Video size={16} />
          </button>
          <button className="p-2 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors">
            <MoreVertical size={16} />
          </button>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto px-5 py-5 space-y-1 custom-scrollbar">
        {/* Date separator */}
        <div className="flex items-center justify-center mb-5">
          <span className="text-[10px] text-[var(--text-disabled)] bg-white/[0.03] border border-[var(--border-subtle)] px-3 py-1 rounded-full">
            {t.messages.today}
          </span>
        </div>

        {activeConversation.messages.map((msg, idx) => (
          <MessageBubble
            key={msg.id}
            msg={msg}
            isLast={idx === activeConversation.messages.length - 1}
          />
        ))}

        {/* Typing indicator */}
        {isTyping && (
          <div className="flex justify-start mb-2">
            <div className="bg-white/[0.05] border border-[var(--border-subtle)] rounded-2xl rounded-bl-md px-4 py-3 flex items-center gap-1.5">
              <span className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <span className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
              <span className="w-2 h-2 bg-gray-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
            </div>
          </div>
        )}

        <div ref={messagesEndRef} />
      </div>

      {/* Input bar */}
      <div className="px-5 py-4 border-t border-[var(--border-subtle)]">
        <div className="flex items-center gap-2 bg-white/[0.03] border border-white/[0.06] rounded-2xl px-4 py-2 focus-within:border-purple-500/40 transition-colors">
          <button
            className="p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors flex-shrink-0"
            title={t.messages.attachFile}
          >
            <Paperclip size={18} />
          </button>
          <button
            className="p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors flex-shrink-0"
            title={t.messages.image}
          >
            <ImageIcon size={18} />
          </button>
          <input
            ref={inputRef}
            type="text"
            placeholder={t.messages.writePlaceholder}
            value={messageInput}
            onChange={e => setMessageInput(e.target.value)}
            onKeyDown={handleKeyDown}
            className="flex-1 bg-transparent text-sm text-white placeholder-gray-500 focus:outline-none py-1"
          />
          <button
            className="p-1.5 rounded-lg hover:bg-white/[0.06] text-gray-500 hover:text-gray-300 transition-colors flex-shrink-0"
            title={t.messages.emoji}
            onClick={() => setShowEmojiHint(prev => !prev)}
          >
            <Smile size={18} />
          </button>
          <button
            onClick={handleSendMessage}
            disabled={!messageInput.trim()}
            className={`p-2 rounded-xl flex-shrink-0 transition-all ${
              messageInput.trim()
                ? 'bg-purple-500 hover:bg-purple-600 text-white shadow-lg shadow-purple-500/20'
                : 'bg-white/[0.03] text-[var(--text-disabled)] cursor-not-allowed'
            }`}
            title={t.messages.send}
          >
            <Send size={16} />
          </button>
        </div>
        {showEmojiHint && (
          <p className="text-[10px] text-[var(--text-disabled)] mt-1.5 px-2">{t.messages.emojiComingSoon}</p>
        )}
      </div>
    </div>
  );

  // ---------------------------------------------------------------------------
  // MAIN RENDER
  // ---------------------------------------------------------------------------

  return (
    <div className="page-enter flex flex-col">
      <PageHeader title={t.messages.pageTitle} description={t.messages.pageDesc} />
      {/* Page header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-4">
          <button
            onClick={onBack}
            className="flex items-center justify-center w-10 h-10 rounded-2xl bg-white/[0.03] border border-white/[0.06] text-gray-400 hover:text-white hover:border-white/[0.15] transition-all"
          >
            <ArrowLeft size={18} />
          </button>
          <div>
            <h1 className="text-2xl sm:text-3xl font-sans font-bold text-white flex items-center gap-3">
              <div className="w-10 h-10 rounded-2xl bg-purple-500/10 flex items-center justify-center text-purple-400 border border-purple-500/20">
                <MessageSquare size={20} />
              </div>
              {t.messages.messaging}
              {totalUnread > 0 && (
                <span className="text-xs font-bold bg-purple-500 text-white px-2.5 py-1 rounded-full">
                  {totalUnread}
                </span>
              )}
            </h1>
            <p className="text-gray-500 text-sm mt-1">
              {conversations.length} {t.messages.conversationCount}{conversations.length > 1 ? 's' : ''}
              {totalUnread > 0 && <span className="text-purple-400"> &middot; {totalUnread} {t.messages.unreadCount}{totalUnread > 1 ? 's' : ''}</span>}
            </p>
          </div>
        </div>

        {user && (
          <div className="hidden sm:flex items-center gap-2 text-xs text-gray-500 bg-white/[0.03] border border-[var(--border-subtle)] px-3 py-1.5 rounded-full">
            <Circle size={6} className="fill-green-400 text-green-400" />
            {user.name}
          </div>
        )}
      </div>

      {/* Two-column layout */}
      <div className="flex-1 flex bg-white/[0.03] border border-white/[0.06] rounded-2xl overflow-hidden" style={{ minHeight: 'calc(100vh - 200px)' }}>
        {ConversationListPanel}
        {MessageThreadPanel}
      </div>
    </div>
  );
};

export default Messages;
